class Solution:
    def removeOccurrences(self, s, part):
        """
        :type s: str
        :type part: str
        :rtype: str
        """
        stack = []
        part_len = len(part)

        for char in s:
            stack.append(char)

            # Check if last len(part) chars match part
            if len(stack) >= part_len and ''.join(stack[-part_len:]) == part:
                for _ in range(part_len):
                    stack.pop()

        return ''.join(stack)
